import nodemailer, { Transporter } from 'nodemailer';

export interface EmailOptions {
  to: string;
  subject: string;
  html: string;
}

export class EmailService {
  /**
   * Crea un transporter fresco en cada llamada para garantizar que las
   * variables de entorno estén cargadas y que un fallo previo no bloquee
   * los envíos siguientes.
   */
  private createTransporter(): Transporter {
    if (!process.env.SMTP_USER || !process.env.SMTP_PASS) {
      throw new Error('Credenciales SMTP no configuradas. Configura SMTP_USER y SMTP_PASS en el archivo .env');
    }

    const port = parseInt(process.env.SMTP_PORT || '465');
    // Puerto 465 siempre usa SSL (secure=true). Otros puertos usan STARTTLS (secure=false).
    const secure = port === 465 ? true : process.env.SMTP_SECURE === 'true';

    return nodemailer.createTransport({
      host: process.env.SMTP_HOST || 'smtp.hostinger.com',
      port,
      secure,
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
      },
      // Timeout generoso para evitar cuelgues silenciosos
      connectionTimeout: 10000,
      greetingTimeout: 10000,
      socketTimeout: 15000,
    });
  }

  private getFromAddress(): string {
    return process.env.SMTP_FROM || process.env.SMTP_USER || 'noreply@pruebalo.com';
  }

  async sendEmail(options: EmailOptions): Promise<void> {
    const transporter = this.createTransporter();
    try {
      const info = await transporter.sendMail({
        from: this.getFromAddress(),
        to: options.to,
        subject: options.subject,
        html: options.html,
      });
      console.log('[Email] Enviado:', info.messageId, '→', options.to);
    } catch (error: any) {
      console.error('[Email] Error al enviar a', options.to, ':', error?.message || error);
      throw new Error('Error al enviar email: ' + (error?.message || 'desconocido'));
    } finally {
      transporter.close();
    }
  }

  async verifyConnection(): Promise<boolean> {
    try {
      const transporter = this.createTransporter();
      await transporter.verify();
      transporter.close();
      console.log('[Email] Conexión SMTP verificada correctamente');
      return true;
    } catch (error: any) {
      console.error('[Email] Error al verificar conexión SMTP:', error?.message || error);
      return false;
    }
  }
}

export const emailService = new EmailService();

import https from 'https';

export interface BrevoEmailOptions {
  to: string;
  subject: string;
  html: string;
  fromName?: string;
}

export interface BrevoSendResult {
  messageId: string;
  accepted: string[];
  rejected: string[];
}

export interface BrevoMessageStatus {
  email: string;
  messageId: string;
  status: 'sent' | 'delivered' | 'opened' | 'clicked' | 'bounced' | 'blocked';
  sentAt?: string;
  deliveredAt?: string;
  openedAt?: string;
  clickedAt?: string;
}

export class BrevoCampaignService {
  private apiKey: string;
  private senderEmail: string;
  private senderName: string;

  constructor() {
    this.apiKey = process.env.BREVO_API_KEY || '';
    const fromStr = process.env.SMTP_FROM || process.env.SMTP_USER || 'info@lookitry.com';
    const parsed = this.parseSender(fromStr);
    this.senderEmail = parsed.email;
    this.senderName = process.env.SMTP_FROM_NAME || parsed.name || 'Lookitry';
  }

  private parseSender(senderStr: string): { name?: string; email: string } {
    const match = senderStr.match(/^(.*)<(.*)>$/);
    if (match) {
      return {
        name: match[1].trim(),
        email: match[2].trim()
      };
    }
    return { email: senderStr.trim() };
  }

  async verifyConnection(): Promise<boolean> {
    try {
      await this.makeRequest('/smtp/statistics/reports', 'GET');
      return true;
    } catch (error) {
      console.error('[Brevo] Connection verification failed:', error);
      return false;
    }
  }

  private async makeRequest(path: string, method: string, body?: object): Promise<any> {
    return new Promise((resolve, reject) => {
      if (!this.apiKey) {
        return reject(new Error('BREVO_API_KEY no configurada'));
      }

      const options = {
        hostname: 'api.brevo.com',
        port: 443,
        path: `/v3${path}`,
        method,
        headers: {
          'Content-Type': 'application/json',
          'api-key': this.apiKey,
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => (data += chunk));
        res.on('end', () => {
          let parsed: any;
          try {
            parsed = JSON.parse(data);
          } catch {
            parsed = data;
          }

          if (res.statusCode && (res.statusCode < 200 || res.statusCode >= 300)) {
            const error: any = new Error(parsed?.message || `Brevo Error ${res.statusCode}`);
            error.statusCode = res.statusCode;
            error.response = parsed;
            console.error(`[Brevo] API Error (${res.statusCode}):`, JSON.stringify(parsed, null, 2));
            return reject(error);
          }
          resolve(parsed);
        });
      });

      req.on('error', reject);

      if (body) {
        req.write(JSON.stringify(body));
      }
      req.end();
    });
  }

  async sendEmail(options: BrevoEmailOptions): Promise<BrevoSendResult> {
    const payload = {
      sender: {
        name: options.fromName || this.senderName,
        email: this.senderEmail,
      },
      to: [{ email: options.to }],
      subject: options.subject,
      htmlContent: options.html,
    };

    const result = await this.makeRequest('/smtp/email', 'POST', payload);

    return {
      messageId: result.messageId || result['message-id'] || '',
      accepted: result.to || [options.to],
      rejected: result.rejected || [],
    };
  }

  async sendBatchEmails(
    emails: Array<{ to: string; subject: string; html: string; fromName?: string }>
  ): Promise<{ successful: number; failed: number; results: BrevoSendResult[] }> {
    if (!this.apiKey) {
      throw new Error('BREVO_API_KEY no configurada');
    }

    const payload = {
      sender: {
        name: this.senderName,
        email: this.senderEmail,
      },
      to: emails.map((e) => ({ email: e.to })),
      subject: emails[0]?.subject || 'Email de Lookitry',
      htmlContent: emails[0]?.html || '',
    };

    try {
      const result = await this.makeRequest('/smtp/email', 'POST', payload);
      return {
        successful: emails.length,
        failed: 0,
        results: [
          {
            messageId: result.messageId || result['message-id'] || '',
            accepted: result.to || emails.map((e) => e.to),
            rejected: result.rejected || [],
          },
        ],
      };
    } catch (error: any) {
      console.error('[Brevo] Error sending batch:', error);
      return {
        successful: 0,
        failed: emails.length,
        results: [],
      };
    }
  }

  async getEmailStatus(messageId: string): Promise<BrevoMessageStatus | null> {
    if (!this.apiKey) {
      return null;
    }

    try {
      const result = await this.makeRequest(`/smtp/emails/${messageId}/details`, 'GET');
      return {
        email: result.email || '',
        messageId,
        status: this.mapBrevoStatus(result.status),
        sentAt: result.date,
        deliveredAt: result.deliveredAt,
        openedAt: result.openedAt,
        clickedAt: result.clickedAt,
      };
    } catch (error) {
      console.error('[Brevo] Error getting email status:', error);
      return null;
    }
  }

  private mapBrevoStatus(status: string): BrevoMessageStatus['status'] {
    const statusMap: Record<string, BrevoMessageStatus['status']> = {
      sent: 'sent',
      delivered: 'delivered',
      opened: 'opened',
      clicked: 'clicked',
      bounced: 'bounced',
      blocked: 'blocked',
    };
    return statusMap[status?.toLowerCase()] || 'sent';
  }
}

export const brevoCampaignService = new BrevoCampaignService();

import { Request, Response } from 'express';
import { AuthService } from '../services/auth.service';
import { EmailService } from '../services/email.service';
import { verifyEmailTemplate, passwordResetTemplate } from '../templates/email-templates';
import { RegisterBrandDto, LoginDto } from '../types';
import { AuthRequest } from '../middleware/auth';
import { generateToken } from '../utils/jwt';
import { supabaseAdmin } from '../config/supabase';
import { loginWithGoogle, verifyGoogleAccessToken } from '../services/google-auth.service';

const authService = new AuthService();
const emailService = new EmailService();

/** Emite el JWT como cookie HTTP-Only segura */
const IS_PROD = process.env.NODE_ENV === 'production';
const COOKIE_DOMAIN = process.env.COOKIE_DOMAIN;

function setCookieToken(res: Response, token: string): void {
  const cookieOptions: any = {
    httpOnly: true,
    secure: IS_PROD,           // Solo HTTPS en producción
    sameSite: 'lax', // 'lax' para compatibilidad con logout cross-origin
    maxAge: 30 * 24 * 60 * 60 * 1000,  // 30 días en ms
    path: '/',
  };

  if (COOKIE_DOMAIN && IS_PROD) {
    cookieOptions.domain = COOKIE_DOMAIN;
  }

  res.cookie('token', token, cookieOptions);
}

export class AuthController {
  async register(req: Request, res: Response) {
    try {
      // Si el usuario ya tiene sesión activa, rechazar el registro
      const token = (req as any).cookies?.token || req.headers.authorization?.replace('Bearer ', '');
      if (token) {
        try {
          const { verifyToken } = await import('../utils/jwt');
          const payload = verifyToken(token);
          if (payload.brandId) {
            return res.status(200).json({
              needsOnboarding: false,
              redirectTo: '/dashboard',
              message: 'Ya tienes una sesión activa. Redirigiendo...',
            });
          }
        } catch {}
      }

      const data: RegisterBrandDto = req.body;

      if (!data.email || !data.password || !data.name || !data.slug) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Todos los campos son requeridos' });
      }

      if (!data.contact_name || data.contact_name.trim().length < 3) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El nombre completo es requerido (mínimo 3 caracteres)' });
      }

      // Verificar Turnstile si está habilitado
      // Se omite en el flujo post-pago (cuando viene con referencia de pago Wompi)
      const turnstileEnabled = process.env.TURNSTILE_ENABLED === 'true';
      const isPostPayment = !!req.body.ref;
      if (turnstileEnabled && !isPostPayment) {
        const token = req.body.turnstileToken;
        if (!token) {
          return res.status(400).json({ error: 'CAPTCHA_REQUIRED', message: 'Verificación de seguridad requerida' });
        }
        const ip = req.ip || req.headers['x-forwarded-for']?.toString().split(',')[0].trim() || '';
        const formData = new URLSearchParams();
        formData.append('secret', process.env.TURNSTILE_SECRET_KEY || '');
        formData.append('response', token);
        if (ip) formData.append('remoteip', ip);

        const verifyRes = await fetch('https://challenges.cloudflare.com/turnstile/v0/siteverify', {
          method: 'POST',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: formData.toString(),
        });
        const verifyData = await verifyRes.json() as { success: boolean; 'error-codes'?: string[] };
        if (!verifyData.success) {
          console.error('[Turnstile] Verificación fallida:', verifyData['error-codes']);
          return res.status(400).json({ error: 'CAPTCHA_FAILED', message: 'Verificación de seguridad fallida. Intenta de nuevo.' });
        }
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(data.email)) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Formato de email inválido' });
      }

      // Bloquear dominios de email desechables
      const disposableDomains = ['mailinator.com','guerrillamail.com','tempmail.com','throwam.com','yopmail.com','sharklasers.com','grr.la','guerrillamail.info','spam4.me','trashmail.com','trashmail.me','dispostable.com','fakeinbox.com','maildrop.cc','mailnull.com','spamgourmet.com','tempr.email','discard.email','10minutemail.com','minutemail.com','throwaway.email','getairmail.com','filzmail.com','spamgourmet.net','spamgourmet.org'];
      const emailDomain = data.email.split('@')[1]?.toLowerCase();
      if (emailDomain && disposableDomains.includes(emailDomain)) {
        return res.status(400).json({ error: 'DISPOSABLE_EMAIL', message: 'No se permiten correos temporales. Usa tu correo real.' });
      }

      const slugRegex = /^[a-z0-9-]+$/;
      if (!slugRegex.test(data.slug)) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El slug solo puede contener letras minúsculas, números y guiones' });
      }

      if (data.slug.length < 3 || data.slug.length > 50) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El slug debe tener entre 3 y 50 caracteres' });
      }

      const reservedSlugs = [
        'admin', 'api', 'app', 'blog', 'checkout', 'dashboard', 'home', 'login', 
        'logout', 'register', 'signup', 'signin', 'password', 'reset', 'forgot',
        'account', 'accounts', 'auth', 'authorize', 'callback', 'contact', 'docs',
        'documentation', 'download', 'downloads', 'email', 'help', 'home', 'jobs',
        'legal', 'market', 'markets', 'news', 'onboarding', 'payment', 'payments',
        'plans', 'pricing', 'privacy', 'products', 'profile', 'public', 'root',
        'secure', 'security', 'settings', 'shop', 'site', 'sites', 'static', 
        'support', 'terms', 'tools', 'trial', 'trial-checkout', 'upload', 'uploads',
        'users', 'verify', 'webhook', 'webhooks', 'www', 'mail', 'email', 'support', 
        'help', 'docs', 'documentation', 'admin', 'superadmin', 'root', 'system',
        'null', 'undefined', 'true', 'false', 'none', 'default', 'main', 'test',
        'demo', 'dev', 'development', 'staging', 'stage', 'prod', 'production',
        'lookitry', 'lookitrycom', 'wwwlookitry', 'lookitrycom', 'mobile', 'desktop'
      ];
      if (reservedSlugs.includes(data.slug.toLowerCase())) {
        return res.status(400).json({ error: 'SLUG_RESERVED', message: 'Este slug está reservado. Elige otro.' });
      }

      if (data.password.length < 8) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La contraseña debe tener al menos 8 caracteres, una mayúscula, una minúscula, un número y un carácter especial' });
      }

      // Validar complejidad de contraseña
      const hasUppercase = /[A-Z]/.test(data.password);
      const hasLowercase = /[a-z]/.test(data.password);
      const hasNumber = /[0-9]/.test(data.password);
      const hasSpecial = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(data.password);
      
      if (!hasUppercase || !hasLowercase || !hasNumber || !hasSpecial) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La contraseña debe contener mayúscula, minúscula, número y carácter especial' });
      }

      const result = await authService.register({
        ...data,
        ip: req.ip || req.headers['x-forwarded-for']?.toString().split(',')[0].trim() || 'unknown',
        fingerprint: req.body.fingerprint || null,
      });

      // Enviar email de verificacion solo si NO requiere pago por prueba.
      // Si requiresTrialPayment=true, el email se envia desde el webhook cuando
      // el pago del trial queda confirmado. Asi evitamos que alguien verifique
      // el email sin haber completado el pago de la prueba.
      if (result.verificationToken && !result.requiresTrialPayment) {
        const frontendUrl = (process.env.NODE_ENV === 'development' || !process.env.FRONTEND_URL) ? 'http://localhost:3000' : process.env.FRONTEND_URL;
        const verifyUrl = `${frontendUrl}/auth/verify?token=${result.verificationToken}`;
        emailService.sendEmail({
          to: result.brand.email,
          subject: 'Confirma tu correo — Lookitry',
          html: verifyEmailTemplate({ name: result.brand.name, email: result.brand.email }, verifyUrl),
        }).catch(err => console.error('[Auth] Error enviando email de verificación:', err));
      }

      // Emitir token como cookie HTTP-Only (más seguro que localStorage)
      if (result.token) setCookieToken(res, result.token);

      // Construir redirectTo basado en plan seleccionado (para flujo post-registro)
      const plan = req.body.plan?.toUpperCase();
      const months = parseInt(req.body.months || '1', 10);
      let redirectTo = '/checkout';
      if (plan && ['TRIAL', 'BASIC', 'PRO', 'LANDING'].includes(plan)) {
        const params = new URLSearchParams();
        params.set('plan', plan);
        if (plan !== 'TRIAL' && [3, 6, 12].includes(months)) {
          params.set('months', String(months));
        }
        redirectTo = `/checkout?${params.toString()}`;
      }

      return res.status(201).json({ ...result, redirectTo });
    } catch (error: any) {
      console.error('Error en register:', error);

      if (error.message.includes('email') && error.message.includes('ya')) {
        return res.status(409).json({ error: 'EMAIL_EXISTS', message: 'Este correo ya está registrado. ¿Ya tienes cuenta?' });
      }

      if (error.message.includes('slug') && error.message.includes('uso')) {
        return res.status(409).json({ error: 'SLUG_TAKEN', message: 'Este URL ya está en uso. Prueba otro.' });
      }

      if (error.message === 'TRIAL_ABUSE') {
        return res.status(429).json({
          error: 'TRIAL_ABUSE',
          message: 'Ya existe una cuenta de prueba registrada desde este dispositivo o red. Puedes contratar un plan directamente.',
        });
      }

      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al registrar la marca' });
    }
  }

  async verifyEmail(req: Request, res: Response) {
    try {
      const { token } = req.query;
      if (!token || typeof token !== 'string') {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Token requerido' });
      }

      const result = await authService.verifyEmail(token) as { ok: boolean; message: string; brandId?: string };
      if (!result.ok) {
        return res.status(400).json({ error: 'INVALID_TOKEN', message: result.message });
      }

      // Si se verificó correctamente, emitir cookie de sesión (Auto-login)
      if (result.brandId) {
        const fullBrand = await authService.getBrandById(result.brandId);
        if (fullBrand) {
          const newToken = generateToken({ brandId: fullBrand.id, email: fullBrand.email });
          setCookieToken(res, newToken);
          
          // Disparar correo de Bienvenida con los datos del plan tras la verificación exitosa.
          // skipPreferenceCheck=true porque la tabla notification_preferences puede estar
          // vacía para esta marca (recién creada).
          import('../services/notification.service')
            .then(({ notificationService }) => notificationService.sendWelcomeEmail(fullBrand as any, true))
            .catch(err => console.error('[Auth] Error importando notificationService:', err));
          
          return res.status(200).json({ 
            message: result.message,
            token: newToken,
            brand: {
              id: fullBrand.id,
              name: fullBrand.name,
              email: fullBrand.email,
              slug: fullBrand.slug,
              plan: fullBrand.plan,
              emailVerified: true
            }
          });
        }
      }

      return res.status(200).json({ message: result.message });
    } catch (error: any) {
      console.error('Error en verifyEmail:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al verificar el correo' });
    }
  }

  async login(req: Request, res: Response) {
    try {
      const data: LoginDto = req.body;

      if (!data.email || !data.password) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Email y contraseña son requeridos' });
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(data.email)) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Formato de email inválido' });
      }

      const result = await authService.login(data);
      // Emitir token como cookie HTTP-Only (más seguro que localStorage)
      if (result.token) setCookieToken(res, result.token);
      return res.status(200).json(result);
    } catch (error: any) {
      console.error('Error en login:', error);

      if (error.message === 'Credenciales inválidas') {
        return res.status(401).json({ error: 'INVALID_CREDENTIALS', message: error.message });
      }

      if (error.message === 'EMAIL_NOT_VERIFIED') {
        return res.status(403).json({ error: 'EMAIL_NOT_VERIFIED', message: 'Debes verificar tu correo electrónico antes de iniciar sesión' });
      }

      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al iniciar sesión' });
    }
  }

  async forgotPassword(req: Request, res: Response) {
    try {
      const { email } = req.body;
      if (!email) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Email requerido' });
      }

      const frontendUrl = process.env.FRONTEND_URL || (process.env.NODE_ENV === 'development' ? 'http://localhost:3000' : 'https://lookitry.com');
      const { brand, token } = await authService.requestPasswordResetGetToken(email);

      // Siempre responder OK para no revelar si el email existe
      if (brand && token) {
        const resetUrl = `${frontendUrl}/auth/reset-password?token=${token}`;
        emailService.sendEmail({
          to: brand.email,
          subject: 'Recuperar contraseña — Lookitry',
          html: passwordResetTemplate({ name: brand.name, email: brand.email }, resetUrl),
        }).catch(err => console.error('[Auth] Error enviando email de reset:', err));
      }

      return res.status(200).json({ message: 'Si el email existe, recibirás un enlace para restablecer tu contraseña.' });
    } catch (error: any) {
      console.error('Error en forgotPassword:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al procesar la solicitud' });
    }
  }

  async resetPassword(req: Request, res: Response) {
    try {
      const { token, password } = req.body;
      if (!token || !password) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Token y contraseña son requeridos' });
      }
      if (password.length < 8) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La contraseña debe tener al menos 8 caracteres, una mayúscula, una minúscula, un número y un carácter especial' });
      }
      
      const hasUppercase = /[A-Z]/.test(password);
      const hasLowercase = /[a-z]/.test(password);
      const hasNumber = /[0-9]/.test(password);
      const hasSpecial = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password);
      
      if (!hasUppercase || !hasLowercase || !hasNumber || !hasSpecial) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La contraseña debe contener mayúscula, minúscula, número y carácter especial' });
      }

      await authService.resetPassword(token, password);
      return res.status(200).json({ message: 'Contraseña restablecida correctamente' });
    } catch (error: any) {
      console.error('Error en resetPassword:', error);
      if (error.message === 'TOKEN_INVALID' || error.message === 'TOKEN_EXPIRED') {
        return res.status(400).json({ error: error.message, message: 'El enlace es inválido o ha expirado. Solicita uno nuevo.' });
      }
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al restablecer la contraseña' });
    }
  }

  async resendVerification(req: Request, res: Response) {
    try {
      const { email } = req.body;
      if (!email) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Email requerido' });
      }

      const frontendUrl = process.env.FRONTEND_URL || (process.env.NODE_ENV === 'development' ? 'http://localhost:3000' : 'https://lookitry.com');
      const { brand, token } = await authService.resendVerificationEmail(email);

      if (brand && token) {
        const verifyUrl = `${frontendUrl}/auth/verify?token=${token}`;
        emailService.sendEmail({
          to: brand.email,
          subject: 'Confirma tu correo — Lookitry',
          html: verifyEmailTemplate({ name: brand.name, email: brand.email }, verifyUrl),
        }).catch(err => console.error('[Auth] Error reenviando email de verificación:', err));
      }

      // Siempre responder OK para no revelar si el email existe
      return res.status(200).json({ message: 'Si el email está pendiente de verificación, recibirás un nuevo enlace.' });
    } catch (error: any) {
      console.error('Error en resendVerification:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al reenviar el correo' });
    }
  }

  async changePassword(req: AuthRequest, res: Response) {
    try {
      const brandId = req.brand!.id;
      const { currentPassword, newPassword } = req.body;

      if (!currentPassword || !newPassword) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Contraseña actual y nueva son requeridas' });
      }
      if (newPassword.length < 8) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La nueva contraseña debe tener al menos 8 caracteres, una mayúscula, una minúscula, un número y un carácter especial' });
      }
      
      const hasUppercase = /[A-Z]/.test(newPassword);
      const hasLowercase = /[a-z]/.test(newPassword);
      const hasNumber = /[0-9]/.test(newPassword);
      const hasSpecial = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(newPassword);
      
      if (!hasUppercase || !hasLowercase || !hasNumber || !hasSpecial) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'La contraseña debe contener mayúscula, minúscula, número y carácter especial' });
      }

      await authService.changePassword(brandId, currentPassword, newPassword);
      return res.status(200).json({ message: 'Contraseña actualizada correctamente' });
    } catch (error: any) {
      console.error('Error en changePassword:', error);
      if (error.message === 'WRONG_PASSWORD') {
        return res.status(401).json({ error: 'WRONG_PASSWORD', message: 'La contraseña actual es incorrecta' });
      }
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al cambiar la contraseña' });
    }
  }

  async checkEmail(req: Request, res: Response) {
    try {
      const { email } = req.query;

      if (!email || typeof email !== 'string') {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Email requerido' });
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(email)) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Formato de email inválido' });
      }

      const { data: brand, error } = await supabaseAdmin
        .from('brands')
        .select('id, name, email, plan, subscription_status')
        .eq('email', email.toLowerCase())
        .maybeSingle();

      if (error) {
        console.error('[checkEmail] Error consultando brand:', error);
        return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al verificar email' });
      }

      if (!brand) {
        return res.status(200).json({ exists: false });
      }

      return res.status(200).json({
        exists: true,
        plan: brand.plan,
        subscription_status: brand.subscription_status,
      });
    } catch (error: any) {
      console.error('Error en checkEmail:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al verificar email' });
    }
  }

  async googleLogin(req: Request, res: Response) {
    try {
      // permite login con cualquier cuenta Google (incluso si hay cookie activa)
      // El usuario elegirá cuenta en el diálogo de Google gracias a prompt: 'select_account'

      const { credential, accessToken } = req.body;

      let result: any;

      if (accessToken) {
        // OAuth2 flow (popup) - validar access token en backend
        const userInfo = await verifyGoogleAccessToken(accessToken);
        const { findOrCreateBrandFromGoogle } = await import('../services/google-auth.service');
        result = await findOrCreateBrandFromGoogle(userInfo);
      } else if (credential) {
        // ID Token flow (One Tap)
        result = await loginWithGoogle(credential);
      } else {
        return res.status(400).json({ error: 'CREDENTIAL_REQUIRED', message: 'Credential o accessToken de Google requerido' });
      }

      if (result.token) setCookieToken(res, result.token);

      return res.status(200).json({
        token: result.token,
        brand: {
          id: result.brand.id,
          name: result.brand.name,
          email: result.brand.email,
          slug: result.brand.slug || null,
          plan: result.brand.plan || 'TRIAL',
          emailVerified: true,
          authProvider: result.brand.auth_provider || 'google',
        },
        needsOnboarding: result.needsOnboarding,
        isNewBrand: result.isNewBrand,
        accountLinked: result.accountLinked,
        pendingRegistrationId: result.pendingRegistrationId || null,
        redirectTo: result.redirectTo || null,
      });
  } catch (error: any) {
    const errMsg = error?.message || 'UNKNOWN_ERROR';
    console.error('Error en googleLogin:', errMsg, error?.stack);

    if (errMsg === 'GOOGLE_NOT_CONFIGURED') {
      return res.status(503).json({ error: 'SERVICE_NOT_CONFIGURED', message: 'Google Auth no está configurado' });
    }

    if (errMsg === 'DISPOSABLE_EMAIL') {
      return res.status(400).json({ error: 'DISPOSABLE_EMAIL', message: 'No se permiten correos temporales. Usa tu correo real.' });
    }

    if (
      errMsg === 'GOOGLE_TOKEN_INVALID' ||
      errMsg === 'GOOGLE_AUDIENCE_MISMATCH' ||
      errMsg === 'GOOGLE_ACCESS_TOKEN_INVALID'
    ) {
      return res.status(401).json({ error: 'INVALID_GOOGLE_TOKEN', message: 'Token de Google inválido' });
    }

    return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al iniciar sesión con Google', detail: errMsg });
  }
  }

  async completeGoogleOnboarding(req: AuthRequest, res: Response) {
    try {
      const { ref, name, slug } = req.body;

      if (!name || !slug) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Nombre de marca y slug son requeridos' });
      }

      const slugRegex = /^[a-z0-9-]+$/;
      if (!slugRegex.test(slug)) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El slug solo puede contener letras minúsculas, números y guiones' });
      }

      if (slug.length < 3 || slug.length > 50) {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'El slug debe tener entre 3 y 50 caracteres' });
      }

      const reservedSlugs = [
        'admin', 'api', 'app', 'blog', 'checkout', 'dashboard', 'home', 'login', 
        'logout', 'register', 'signup', 'signin', 'password', 'reset', 'forgot',
        'account', 'accounts', 'auth', 'authorize', 'callback', 'contact', 'docs',
        'documentation', 'download', 'downloads', 'email', 'help', 'jobs',
        'legal', 'market', 'markets', 'news', 'onboarding', 'payment', 'payments',
        'plans', 'pricing', 'privacy', 'products', 'profile', 'public', 'root',
        'secure', 'security', 'settings', 'shop', 'site', 'sites', 'static', 
        'support', 'terms', 'tools', 'trial', 'trial-checkout', 'upload', 'uploads',
        'users', 'verify', 'webhook', 'webhooks', 'www', 'mail', 'support', 
        'help', 'docs', 'documentation', 'superadmin', 'system', 'null', 'undefined',
        'true', 'false', 'none', 'default', 'main', 'test', 'demo', 'dev', 
        'development', 'staging', 'stage', 'prod', 'production', 'lookitry', 
        'lookitrycom', 'wwwlookitry', 'mobile', 'desktop'
      ];
      if (reservedSlugs.includes(slug.toLowerCase())) {
        return res.status(400).json({ error: 'SLUG_RESERVED', message: 'Este slug está reservado. Elige otro.' });
      }

      // Verificar slug único
      const { data: existingSlug } = await supabaseAdmin
        .from('brands')
        .select('id')
        .eq('slug', slug)
        .maybeSingle();

      if (existingSlug) {
        return res.status(409).json({ error: 'SLUG_TAKEN', message: 'Este slug ya está en uso. Prueba con otro.' });
      }

      let brandData: any;

      if (ref) {
        // FLUJO NUEVO: Crear marca desde pending_registrations
        const { data: pendingReg, error: pendingError } = await supabaseAdmin
          .from('pending_registrations')
          .select('*')
          .eq('id', ref)
          .maybeSingle();

        if (pendingError || !pendingReg) {
          return res.status(404).json({ error: 'NOT_FOUND', message: 'Registro pendiente no encontrado' });
        }

        // Generar slug bonito basado en el nombre si el slug proporcionado contiene "G-"
        const finalSlug = slug.includes('G-') ? slug : slug;

        // Crear la marca usando los datos de pending_registrations
        const { data: newBrand, error: brandError } = await supabaseAdmin
          .from('brands')
          .insert({
            email: pendingReg.email,
            password: null,
            name: name,
            slug: finalSlug,
            contact_name: pendingReg.brand_name || name,
            google_id: pendingReg.reference?.includes('G-') ? pendingReg.reference.split('-')[1] : null,
            auth_provider: 'google',
            email_verified: true,
            needs_onboarding: false,
            plan: pendingReg.plan || 'TRIAL',
            subscription_status: null,
            trial_end_date: null,
            trial_generations_limit: 0,
            primary_color: '#000000',
            secondary_color: '#ffffff',
          })
          .select('*')
          .single();

        if (brandError) {
          console.error('[GoogleOnboarding] Error creando marca:', brandError);
          return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al crear la marca' });
        }

        // Marcar pending_registrations como completado
        await supabaseAdmin
          .from('pending_registrations')
          .update({ status: 'completed' })
          .eq('id', ref);

        brandData = newBrand;
      } else if (req.brand?.id) {
        // FLUJO LEGACY: Actualizar marca existente (para usuarios que ya tenían marca)
        const { data: updatedBrand, error } = await supabaseAdmin
          .from('brands')
          .update({ name, slug, needs_onboarding: false })
          .eq('id', req.brand.id)
          .select('*')
          .single();

        if (error) {
          console.error('[GoogleOnboarding] Error actualizando marca:', error);
          return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al completar configuración' });
        }

        brandData = updatedBrand;
      } else {
        return res.status(400).json({ error: 'VALIDATION_ERROR', message: 'Se requiere ref o sesión activa' });
      }

      const newToken = generateToken({ brandId: brandData.id, email: brandData.email });
      setCookieToken(res, newToken);

      return res.status(200).json({
        message: 'Configuración completada',
        brand: {
          id: brandData.id,
          name: brandData.name,
          email: brandData.email,
          slug: brandData.slug,
          plan: brandData.plan,
          emailVerified: true,
        },
        token: newToken,
      });
    } catch (error: any) {
      console.error('Error en completeGoogleOnboarding:', error);
      return res.status(500).json({ error: 'INTERNAL_ERROR', message: 'Error al completar configuración' });
    }
  }
}

import bcrypt from 'bcryptjs';
import crypto from 'crypto';
import * as jwt from 'jsonwebtoken';
import { supabaseAdmin } from '../config/supabase';
import { RegisterBrandDto, LoginDto, AuthResponse, Brand } from '../types';
import { generateToken } from '../utils/jwt';
import { pricingService } from './pricing.service';
import { attachLedgerSnapshotToNotes } from '../utils/paymentLedger';
import { recordTrialEvent } from '../utils/brandLifecycle';

// ── Helpers de campaña de trial ───────────────────────────────────────────────

async function getActiveCampaign() {
  const now = new Date().toISOString();
  const { data } = await supabaseAdmin
    .from('trial_campaigns')
    .select('id, trial_days, trial_generations_limit, price_cop, require_card_verification')
    .eq('active', true)
    .or(`ends_at.is.null,ends_at.gt.${now}`)
    .order('created_at', { ascending: false })
    .limit(1)
    .single();
  return data as { id: string; trial_days: number; trial_generations_limit: number; price_cop: number; require_card_verification: boolean } | null;
}

function campaignRequiresTrialPayment(campaign: {
  price_cop?: number | null;
  require_card_verification?: boolean | null;
} | null): boolean {
  if (!campaign) return false;
  if (Number(campaign.price_cop || 0) <= 0) return false;
  return campaign.require_card_verification !== false;
}

async function isTrialAbuse(ip: string, fingerprint: string | null): Promise<boolean> {
  // Verificar bypass y whitelist en payment_settings
  const { data: psData } = await supabaseAdmin
    .from('payment_settings')
    .select('bypass_ip_protection, ip_whitelist')
    .eq('id', 1)
    .single();

  if (psData?.bypass_ip_protection === true) {
    return false;
  }

  // Verificar si la IP está en la whitelist
  if (psData?.ip_whitelist) {
    const whitelist = psData.ip_whitelist.split(',').map((s: string) => s.trim()).filter(Boolean);
    if (whitelist.includes(ip)) {
      return false;
    }
  }

  // Verificar si la IP ya tiene un trial registrado en los últimos 30 días
  const since = new Date();
  since.setDate(since.getDate() - 30);

  const { data: byIp } = await supabaseAdmin
    .from('trial_registrations')
    .select('id')
    .eq('ip_address', ip)
    .gte('created_at', since.toISOString())
    .limit(1)
    .single();

  if (byIp) return true;

  // Verificar fingerprint si se proporcionó
  if (fingerprint) {
    const { data: byFp } = await supabaseAdmin
      .from('trial_registrations')
      .select('id')
      .eq('fingerprint', fingerprint)
      .gte('created_at', since.toISOString())
      .limit(1)
      .single();

    if (byFp) return true;
  }

  return false;
}

async function recordTrialRegistration(brandId: string, ip: string, fingerprint: string | null, campaignId: string) {
  await supabaseAdmin.from('trial_registrations').insert({
  brand_id: brandId,
  ip_address: ip,
  fingerprint: fingerprint || null,
  campaign_id: campaignId,
  });
  }

function createEmailVerificationToken(): string {
  return crypto.randomBytes(32).toString('hex');
}

function validatePasswordComplexity(password: string): { isValid: boolean; message?: string } {
  if (password.length < 8) {
    return { isValid: false, message: 'La contraseña debe tener al menos 8 caracteres' };
  }
  
  if (!/[A-Z]/.test(password)) {
    return { isValid: false, message: 'La contraseña debe contener al menos una letra mayúscula' };
  }
  
  if (!/[a-z]/.test(password)) {
    return { isValid: false, message: 'La contraseña debe contener al menos una letra minúscula' };
  }
  
  if (!/[0-9]/.test(password)) {
    return { isValid: false, message: 'La contraseña debe contener al menos un número' };
  }
  
  if (!/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password)) {
    return { isValid: false, message: 'La contraseña debe contener al menos un carácter especial (!@#$%^&*...)' };
  }
  
  return { isValid: true };
}

  export class AuthService {
  /**
  * Registro seguro después de un pago confirmado (Wompi o PayPal).
  * Valida que la referencia exista, que el status sea 'paid' y la marca no exista aún.
  */
  async registerPostPayment(data: RegisterBrandDto & { ref: string; fingerprint?: string }): Promise<AuthResponse> {
  const { ref, name, slug, password, contact_name, fingerprint } = data;
  const normalizedReference = String(ref || '').toUpperCase();
  const isTrialReference = normalizedReference.startsWith('TRIAL-') || normalizedReference.startsWith('GUEST-TRIAL-');

  // 1. Validar referencia en pending_registrations
  const { data: pending, error: pendingError } = await supabaseAdmin
    .from('pending_registrations')
    .select('*')
    .eq('reference', ref)
    .single();

  if (pendingError || !pending) {
    throw new Error('REFERENCIA_INVALIDA');
  }

  // 2. Verificar estado del pago (Seguridad crítica)
  // Nota: Si aún no has corrido el SQL, esto podría fallar, por lo que añadimos un fallback temporal
  // que asume 'paid' si la columna no existe o si es el flujo antiguo, pero lo ideal es el status.
  const status = (pending as any).status || 'paid'; 
  if (status === 'used') {
    throw new Error('REFERENCIA_YA_UTILIZADA');
  }
  // Si la columna existe y no es 'paid', rechazar
  if ((pending as any).status && (pending as any).status !== 'paid') {
    throw new Error('PAGO_NO_CONFIRMADO');
  }

  // 3. Validar disponibilidad de Email y Slug
  const { data: existingBrand } = await supabaseAdmin.from('brands').select('*').eq('email', pending.email).single();
  
  let targetBrandId: string;
  let verificationToken: string | undefined;

  if (existingBrand) {
    // Si la marca ya existe, verificar la contraseña para vincular el pago
    const isPasswordValid = await bcrypt.compare(password, existingBrand.password);
    if (!isPasswordValid) {
      throw new Error('EL_EMAIL_YA_EXISTE_CONTRASENA_INCORRECTA');
    }
    
    // Si la contraseña es válida, procedemos a actualizar la marca existente
    targetBrandId = existingBrand.id;
    
    // Actualizar plan y fechas en la marca existente
    const months = pending.months || 1;
    const isTrial = isTrialReference || (pending.plan || '').toUpperCase() === 'TRIAL';
    const plan = isTrial ? 'TRIAL' : (pending.plan || 'BASIC').toUpperCase();

    const now = new Date();
    let endDate = new Date(now);
    let trialEndDate: string | null = null;
    let trialLimit = 0;

    if (isTrial) {
      const campaign = await getActiveCampaign();
      const trialDays = campaign?.trial_days || 7;
      trialLimit = campaign?.trial_generations_limit || 15;
      const tDate = new Date(now);
      tDate.setDate(tDate.getDate() + trialDays);
      trialEndDate = tDate.toISOString();
      // El endDate de la suscripcion en si puede ser el mismo que trial o null
      endDate = tDate; 
    } else {
      // BUG #7 FIX: Usar +30*months para ser consistente con calculateExpirationDate()
      // Evita discrepancias de 1-3 días en meses con <31 días (ej. febrero).
      endDate = new Date(now.getTime() + 30 * months * 24 * 60 * 60 * 1000);
    }

    if (!existingBrand.email_verified) {
      verificationToken = existingBrand.email_verification_token || createEmailVerificationToken();
    }

    await supabaseAdmin
      .from('brands')
      .update({
        plan,
        subscription_status: 'active',
        subscription_start_date: now.toISOString(),
        subscription_end_date: endDate.toISOString(),
        trial_end_date: trialEndDate,
        trial_generations_limit: trialLimit,
        trial_payment_status: isTrial ? 'active' : null,
        has_landing_page: pending.includes_landing || existingBrand.has_landing_page || false,
        last_payment_date: now.toISOString(),
        email_verification_token: existingBrand.email_verified ? null : verificationToken,
      })
      .eq('id', targetBrandId);

    console.log(`[AuthService] Pago vinculado exitosamente a cuenta existente: ${pending.email}`);
  } else {
    // Si la marca no existe, crearla normalmente
    const { data: existingSlug } = await supabaseAdmin.from('brands').select('id').eq('slug', slug).single();
    if (existingSlug) throw new Error('El slug ya está en uso');

    const hashedPassword = await bcrypt.hash(password, 10);
    const months = pending.months || 1;
    const isTrial = isTrialReference || (pending.plan || '').toUpperCase() === 'TRIAL';
    const plan = isTrial ? 'TRIAL' : (pending.plan || 'BASIC').toUpperCase();

    const now = new Date();
    let endDate = new Date(now);
    let trialEndDate: string | null = null;
    let trialLimit = 0;

    if (isTrial) {
      const campaign = await getActiveCampaign();
      const trialDays = campaign?.trial_days || 7;
      trialLimit = campaign?.trial_generations_limit || 15;
      const tDate = new Date(now);
      tDate.setDate(tDate.getDate() + trialDays);
      trialEndDate = tDate.toISOString();
      endDate = tDate;
    } else {
      // BUG #7 FIX: Usar +30*months para ser consistente con calculateExpirationDate()
      // Evita discrepancias de 1-3 días en meses con <31 días (ej. febrero).
      endDate = new Date(now.getTime() + 30 * months * 24 * 60 * 60 * 1000);
    }

    verificationToken = createEmailVerificationToken();

    const { data: newBrand, error: createError } = await supabaseAdmin
      .from('brands')
      .insert({
        email: pending.email,
        password: hashedPassword,
        name,
        slug,
        contact_name: contact_name.trim(),
        plan,
        subscription_status: 'active',
        subscription_start_date: new Date().toISOString(),
        subscription_end_date: endDate.toISOString(),
        trial_end_date: trialEndDate,
        trial_generations_limit: trialLimit,
        trial_payment_status: isTrial ? 'active' : null,
        has_landing_page: pending.includes_landing || false,
        email_verified: false,
        email_verification_token: verificationToken,
      })
      .select()
      .single();

    if (createError || !newBrand) {
      throw new Error('Error al crear la cuenta: ' + createError?.message);
    }
    targetBrandId = newBrand.id;
  }

  // 5. MARCAR REFERENCIA COMO UTILIZADA
  await supabaseAdmin
    .from('pending_registrations')
    .update({ status: 'used', updated_at: new Date().toISOString() } as any)
    .eq('reference', ref);

  // 6. Registrar el pago oficial en subscription_payments
  const recordedAmount = Number(pending.amount || 0) > 0
    ? Number(pending.amount)
    : await pricingService.calculateTotal(
        String(pending.plan || 'BASIC').toUpperCase(),
        Number(pending.months || 1),
        Boolean(pending.includes_landing)
      );

  const paymentPayload = {
    brand_id: targetBrandId,
    amount: recordedAmount,
    currency: 'COP',
    payment_date: new Date().toISOString(),
    payment_method: ref.includes('PAYPAL') ? 'paypal' : 'wompi',
    status: 'completed',
    months_paid: pending.months || 1,
    reference: ref,
    notes: `Activación via registro post-pago. Ref: ${ref}. ID Pago: ${(pending as any).payment_id || 'N/A'}.${pending.includes_landing ? ' Incluye Landing Page.' : ''}`
  };

  const finalBrand = await this.getBrandById(targetBrandId);
  if (!finalBrand) throw new Error('Error al recuperar datos de la marca');

  const paymentPayloadWithSnapshot = {
    ...paymentPayload,
    notes: attachLedgerSnapshotToNotes(paymentPayload.notes, {
      version: 1,
      brandId: targetBrandId,
      brandName: finalBrand?.name || name || null,
      brandEmail: finalBrand?.email || pending.email || null,
      brandSlug: finalBrand?.slug || slug || null,
      planPurchased: String(pending.plan || 'BASIC').toUpperCase(),
      billingType: isTrialReference || String(pending.plan || '').toUpperCase() === 'TRIAL' ? 'trial_activation' : 'subscription',
      includesLanding: Boolean(pending.includes_landing),
      brandPlanBefore: existingBrand?.plan || null,
      brandPlanAfter: finalBrand?.plan || null,
    }),
  };

  let { error: paymentInsertError } = await supabaseAdmin.from('subscription_payments').insert(paymentPayloadWithSnapshot);

  if (paymentInsertError?.message?.toLowerCase().includes('reference')) {
    const { reference, ...fallbackPayload } = paymentPayloadWithSnapshot;
    const retry = await supabaseAdmin.from('subscription_payments').insert(fallbackPayload);
    paymentInsertError = retry.error || null;
  }

  if (paymentInsertError) {
    throw new Error('Error al registrar el pago: ' + paymentInsertError.message);
  }

  if ((isTrialReference || (pending.plan || '').toUpperCase() === 'TRIAL') && finalBrand.trial_end_date) {
    await recordTrialEvent(finalBrand.id, 'trial_started', {
      source: 'post_payment_registration',
      trialEndDate: finalBrand.trial_end_date,
    }).catch(() => {});
  }

  const token = generateToken({ brandId: finalBrand.id, email: finalBrand.email });

  return {
    token,
    brand: {
      id: finalBrand.id,
      email: finalBrand.email,
      name: finalBrand.name,
      slug: finalBrand.slug,
      plan: finalBrand.plan,
      api_key: finalBrand.api_key,
    },
    verificationToken,
    isTrial: isTrialReference || (pending.plan || '').toUpperCase() === 'TRIAL',
  };
  }  async register(data: RegisterBrandDto & { ip?: string; fingerprint?: string }): Promise<AuthResponse> {
    // Validar que el email no exista — supabaseAdmin para bypassear RLS
    const { data: existingBrand } = await supabaseAdmin
      .from('brands')
      .select('id')
      .eq('email', data.email)
      .single();

    if (existingBrand) {
      throw new Error('El email ya está registrado');
    }

    // Validar que el slug no exista
    const { data: existingSlug } = await supabaseAdmin
      .from('brands')
      .select('id')
      .eq('slug', data.slug)
      .single();

    if (existingSlug) {
      throw new Error('El slug ya está en uso');
    }

    // Hashear contraseña
    const hashedPassword = await bcrypt.hash(data.password, 10);

    // Verificar si hay campaña de trial activa
    const campaign = await getActiveCampaign();
    let trialEndDate: Date | null = null;

    if (campaign) {
      trialEndDate = new Date();
      trialEndDate.setDate(trialEndDate.getDate() + campaign.trial_days);
    }

    // Crear marca — supabaseAdmin para bypassear RLS en INSERT
    const { data: newBrand, error } = await supabaseAdmin
      .from('brands')
      .insert({
        email: data.email,
        password: hashedPassword,
        name: data.name,
        slug: data.slug,
        contact_name: data.contact_name.trim(),
        phone: data.phone?.trim() || null,
        plan: trialEndDate ? 'TRIAL' : 'BASIC',
        trial_end_date: trialEndDate ? trialEndDate.toISOString() : null,
        trial_generations_limit: trialEndDate ? (campaign?.trial_generations_limit ?? 15) : 0,
        email_verified: false,
        email_verification_token: crypto.randomBytes(32).toString('hex'),
      })
      .select()
      .single();

    if (error || !newBrand) {
      throw new Error('Error al crear la marca: ' + error?.message);
    }

    // Registrar trial para tracking
    if (campaign && trialEndDate) {
      const ip = data.ip || 'unknown';
      const fingerprint = data.fingerprint || null;
      recordTrialRegistration(newBrand.id, ip, fingerprint, campaign.id).catch(() => {});
      recordTrialEvent(newBrand.id, 'trial_started', {
        trialDays: campaign.trial_days,
        trialGenerationsLimit: campaign.trial_generations_limit,
      }).catch(() => {});
    }

    // Generar token
    const token = generateToken({
      brandId: newBrand.id,
      email: newBrand.email,
    });

    const requiresTrialPayment = campaignRequiresTrialPayment(campaign);

    return {
      token,
      brand: {
        id: newBrand.id,
        email: newBrand.email,
        name: newBrand.name,
        slug: newBrand.slug,
        plan: newBrand.plan,
        api_key: newBrand.api_key,
      },
      verificationToken: newBrand.email_verification_token,
      requiresTrialPayment,
      isTrial: !!trialEndDate,
    };
  }

  async login(data: LoginDto): Promise<AuthResponse> {
    // Buscar marca por email — usar supabaseAdmin para bypassear RLS
    const { data: brand, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('email', data.email)
      .single();

    if (error || !brand) {
      throw new Error('Credenciales inválidas');
    }

    // Verificar contraseña
    const isPasswordValid = await bcrypt.compare(data.password, brand.password);

    if (!isPasswordValid) {
      throw new Error('Credenciales inválidas');
    }

    // Generar token
    const token = generateToken({
      brandId: brand.id,
      email: brand.email,
    });

    return {
      token,
      brand: {
        id: brand.id,
        email: brand.email,
        name: brand.name,
        slug: brand.slug,
        plan: brand.plan,
        api_key: brand.api_key,
        emailVerified: brand.email_verified,
        trialEndDate: brand.trial_end_date ?? null,
        trialPaymentStatus: brand.trial_payment_status ?? null,
      },
    };
  }

  async verifyEmail(token: string): Promise<{ ok: boolean; message: string; brandId?: string }> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, email_verified')
      .eq('email_verification_token', token)
      .single();

    if (!brand) {
      return { ok: false, message: 'Token inválido o expirado' };
    }

    if (brand.email_verified) {
      return { ok: true, message: 'El correo ya fue verificado anteriormente' };
    }

    await supabaseAdmin
      .from('brands')
      .update({ email_verified: true, email_verification_token: null })
      .eq('id', brand.id);

    const verifiedBrand = await this.getBrandById(brand.id);
    if (verifiedBrand?.trial_end_date) {
      await recordTrialEvent(brand.id, 'trial_email_verified').catch(() => {});
    }

    return { ok: true, message: 'Correo verificado correctamente', brandId: brand.id };
  }

  async getBrandById(brandId: string): Promise<Brand | null> {
    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('id', brandId)
      .single();

    if (error || !data) {
      return null;
    }

    return data as Brand;
  }

  async getBrandByApiKey(apiKey: string): Promise<Brand | null> {
    if (!apiKey) return null;

    if (apiKey.startsWith('ey')) {
      const jwtSecret = process.env.JWT_SECRET;
      if (jwtSecret) {
        try {
          const decoded = jwt.verify(apiKey, jwtSecret) as any;
          if (decoded.brand_id && decoded.type === 'embed_session') {
            return await this.getBrandById(decoded.brand_id);
          }
        } catch (e) {
          console.warn('[AuthService] JWT erróneo/expirado en auth:', (e as Error).message);
          return null;
        }
      }
    }

    const { data, error } = await supabaseAdmin
      .from('brands')
      .select('*')
      .eq('api_key', apiKey)
      .single();

    if (error || !data) {
      return null;
    }

    return data as Brand;
  }

  async requestPasswordReset(email: string): Promise<void> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, name, email')
      .eq('email', email)
      .single();

    // No revelar si el email existe o no (seguridad)
    if (!brand) return;

    const token = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hora

    await supabaseAdmin
      .from('brands')
      .update({ reset_token: token, reset_token_expires_at: expiresAt.toISOString() })
      .eq('id', brand.id);

    // El caller se encarga de enviar el email
    (brand as any)._resetToken = token;
    (brand as any)._resetExpires = expiresAt;

    // Guardar en el objeto para que el controller lo use
    Object.assign(brand, { _resetToken: token });
  }

  async requestPasswordResetGetToken(email: string): Promise<{ brand: { name: string; email: string } | null; token: string | null }> {
    // Usar supabaseAdmin para bypassear RLS y encontrar la marca por email
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, name, email')
      .eq('email', email)
      .single();

    if (!brand) return { brand: null, token: null };

    const token = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hora

    await supabaseAdmin
      .from('brands')
      .update({ reset_token: token, reset_token_expires_at: expiresAt.toISOString() })
      .eq('id', brand.id);

    return { brand: { name: brand.name, email: brand.email }, token };
  }

  async resetPassword(token: string, newPassword: string): Promise<void> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, reset_token_expires_at')
      .eq('reset_token', token)
      .single();

    if (!brand) throw new Error('TOKEN_INVALID');

    const expiresAt = new Date(brand.reset_token_expires_at);
    if (expiresAt < new Date()) throw new Error('TOKEN_EXPIRED');

    const complexityCheck = validatePasswordComplexity(newPassword);
    if (!complexityCheck.isValid) {
      throw new Error('PASSWORD_TOO_SHORT');
    }

    const hashedPassword = await bcrypt.hash(newPassword, 10);

    await supabaseAdmin
      .from('brands')
      .update({ password: hashedPassword, reset_token: null, reset_token_expires_at: null })
      .eq('id', brand.id);
  }

  async resendVerificationEmail(email: string): Promise<{ brand: { name: string; email: string } | null; token: string | null }> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, name, email, email_verified, email_verification_token')
      .eq('email', email)
      .single();

    if (!brand || brand.email_verified) return { brand: null, token: null };

    // Reusar token existente o generar uno nuevo
    let token = brand.email_verification_token;
    if (!token) {
      token = crypto.randomBytes(32).toString('hex');
      await supabaseAdmin
        .from('brands')
        .update({ email_verification_token: token })
        .eq('id', brand.id);
    }

    return { brand: { name: brand.name, email: brand.email }, token };
  }

  async changePassword(brandId: string, currentPassword: string, newPassword: string): Promise<void> {
    const { data: brand } = await supabaseAdmin
      .from('brands')
      .select('id, password')
      .eq('id', brandId)
      .single();

    if (!brand) throw new Error('NOT_FOUND');

    const isValid = await bcrypt.compare(currentPassword, brand.password);
    if (!isValid) throw new Error('WRONG_PASSWORD');

    const complexityCheck = validatePasswordComplexity(newPassword);
    if (!complexityCheck.isValid) {
      throw new Error(complexityCheck.message);
    }

    if (newPassword === currentPassword) throw new Error('La nueva contraseña debe ser diferente a la actual');

    const hashedPassword = await bcrypt.hash(newPassword, 10);
    await supabaseAdmin
      .from('brands')
      .update({ password: hashedPassword })
      .eq('id', brandId);
  }
}

import { emailService } from './email.service';
import { SubscriptionService } from './subscription.service';
import { notificationPreferencesService } from './notificationPreferences.service';
import { supabaseAdmin } from '../config/supabase';
import { Brand } from '../types';
import { isTrialOperationalBrand } from '../utils/brandLifecycle';
import {
  welcomeEmail,
  completeRegistrationEmail,
  reminder7DaysEmail,
  reminder3DaysEmail,
  expirationTodayEmail,
  suspensionEmail,
  renewalConfirmationEmail,
  usageAlert80Email,
  usageAlert100Email,
  adminWelcomeEmail,
  landingActivatedEmail,
  landingDeletionWarningEmail,
  landingDeletedNoticeEmail,
  referralBonusCreditedEmail,
  referralConvertedNotifierEmail,
} from '../templates/email-templates';

/**
 * NotificationService
 * 
 * Servicio para enviar notificaciones por email a las marcas.
 * Utiliza EmailService y templates de email para enviar diferentes tipos de notificaciones.
 * Respeta las preferencias de notificaciones de cada marca.
 * 
 * Requirements: 13.1, 13.2, 13.3, 13.4, 13.5, 13.6, 13.7, 13.8, 13.10
 */
export class NotificationService {
  private subscriptionService: SubscriptionService;

  constructor() {
    this.subscriptionService = new SubscriptionService();
  }

  /**
   * Formatea un monto en COP (pesos colombianos)
   * 
   * @param amount - Monto numérico
   * @returns Monto formateado como string (ej: "$150.000 COP")
   */
  private formatCOP(amount: number): string {
    return `$${amount.toLocaleString('es-CO')} COP`;
  }

  /**
   * Obtiene el monto del plan de una marca desde pricing_config
   * 
   * @param plan - Tipo de plan ('TRIAL', 'BASIC' o 'PRO')
   * @returns Monto del plan en COP
   */
  private async getPlanAmount(plan: string): Promise<number> {
    try {
      const planUpper = plan.toUpperCase();
      if (planUpper === 'TRIAL') {
        return 20000;
      }

      const planId = plan.toLowerCase(); // 'basic' o 'pro'
      const { data } = await supabaseAdmin
        .from('pricing_config')
        .select('data')
        .eq('id', planId)
        .single();

      if (data?.data?.precio_mensual_cop) {
        const value = data.data.precio_mensual_cop;
        // Sanity check: si por error `pro` quedó con precio de `basic` (o viceversa),
        // usamos fallback para no enviar correos con monto incorrecto.
        if (planUpper === 'PRO' && value < 200000) return 250000;
        if (planUpper === 'BASIC' && value > 200000) return 150000;
        return value;
      }
    } catch (e) {
      console.error('[NotificationService] Error consultando pricing_config:', e);
    }
    // Fallback en caso de error o datos faltantes
    const planUpper = plan.toUpperCase();
    if (planUpper === 'TRIAL') return 20000;
    return planUpper === 'PRO' ? 250000 : 150000;
  }

  private buildPendingRegistrationUrl(reference: string): string {
    const frontendUrl = process.env.FRONTEND_URL || 'https://lookitry.com';
    return `${frontendUrl}/onboarding-post-pago?ref=${encodeURIComponent(reference)}`;
  }

  /**
   * Envía email de bienvenida al registrarse una nueva marca
   *
   * @param brand - Información de la marca
   * @param skipPreferenceCheck - Si es true omite la verificación de preferencias (para cuentas recién creadas)
   *
   * Requirement 13.1: Enviar email de bienvenida con detalles del plan
   */
  async sendWelcomeEmail(brand: Brand, skipPreferenceCheck = false): Promise<void> {
    try {
      // Para cuentas recién creadas las preferencias aún no existen en BD,
      // así que si skipPreferenceCheck es true, saltamos esa verificación.
      if (!skipPreferenceCheck) {
        const emailEnabled = await notificationPreferencesService.isNotificationEnabled(
          brand.id,
          'email'
        );
        if (!emailEnabled) {
          console.log(`⏭️  Email de bienvenida omitido para ${brand.email} (preferencias)`);
          return;
        }
      }

      const effectivePlan = isTrialOperationalBrand(brand) ? 'TRIAL' : brand.plan;
      const amount = this.formatCOP(await this.getPlanAmount(effectivePlan));
      // getDaysRemaining puede fallar si el plan es TRIAL sin sub activa; usar fallback 7
      let daysRemaining = 7;
      try {
        daysRemaining = await this.subscriptionService.getDaysRemaining(brand.id) || 7;
      } catch {
        // silenciar; la marca puede estar en trial sin suscripción
      }

      const html = welcomeEmail(
        { name: brand.name, email: brand.email },
        effectivePlan,
        amount,
        daysRemaining
      );

      await emailService.sendEmail({
        to: brand.email,
        subject: '¡Bienvenido a Lookitry!',
        html,
      });

      console.log(`✅ Email de bienvenida enviado a ${brand.email}`);
    } catch (error) {
      // No relanzar — el email de bienvenida nunca debe bloquear el flujo de registro
      console.error(`❌ Error al enviar email de bienvenida a ${brand.email}:`, error);
    }
  }

  async sendCompleteRegistrationEmail(pending: {
    email: string;
    reference: string;
    plan: string;
    name?: string | null;
    amount?: number | null;
  }): Promise<void> {
    try {
      const plan = pending.plan.toUpperCase();
      if (!['BASIC', 'PRO'].includes(plan)) {
        return;
      }

      const amount = this.formatCOP(
        typeof pending.amount === 'number' && Number.isFinite(pending.amount)
          ? pending.amount
          : await this.getPlanAmount(plan)
      );
      const html = completeRegistrationEmail(
        {
          name: pending.name?.trim() || pending.email,
          email: pending.email,
        },
        plan,
        amount,
        this.buildPendingRegistrationUrl(pending.reference)
      );

      await emailService.sendEmail({
        to: pending.email,
        subject: 'Completa tu registro en Lookitry',
        html,
      });

      console.log(`✅ Email para completar registro enviado a ${pending.email}`);
    } catch (error) {
      console.error(`❌ Error al enviar email de registro pendiente a ${pending.email}:`, error);
    }
  }

  async sendCompleteRegistrationReminderEmail(pending: {
    email: string;
    reference: string;
    plan: string;
    name?: string | null;
    amount?: number | null;
  }): Promise<void> {
    try {
      const plan = pending.plan.toUpperCase();
      if (!['BASIC', 'PRO'].includes(plan)) {
        return;
      }

      const amount = this.formatCOP(
        typeof pending.amount === 'number' && Number.isFinite(pending.amount)
          ? pending.amount
          : await this.getPlanAmount(plan)
      );
      const html = completeRegistrationEmail(
        {
          name: pending.name?.trim() || pending.email,
          email: pending.email,
        },
        plan,
        amount,
        this.buildPendingRegistrationUrl(pending.reference),
        true
      );

      await emailService.sendEmail({
        to: pending.email,
        subject: 'Recordatorio: completa tu registro en Lookitry',
        html,
      });

      console.log(`✅ Recordatorio de registro pendiente enviado a ${pending.email}`);
    } catch (error) {
      console.error(`❌ Error al enviar recordatorio de registro pendiente a ${pending.email}:`, error);
    }
  }

  /**
   * Envía recordatorio de renovación antes del vencimiento
   * 
   * @param brand - Información de la marca
   * @param daysRemaining - Días restantes hasta el vencimiento
   * 
   * Requirements: 13.2, 13.3, 13.4, 13.9, 13.10
   */
  async sendExpirationReminder(brand: Brand, daysRemaining: number): Promise<void> {
    try {
      // Verificar si el email está habilitado
      const emailEnabled = await notificationPreferencesService.isNotificationEnabled(
        brand.id,
        'email'
      );

      if (!emailEnabled) {
        console.log(`⏭️  Recordatorio omitido para ${brand.email} (email deshabilitado)`);
        return;
      }

      // Verificar preferencias específicas según los días
      if (daysRemaining === 7) {
        const reminder7Enabled = await notificationPreferencesService.isNotificationEnabled(
          brand.id,
          'reminder_7days'
        );
        if (!reminder7Enabled) {
          console.log(`⏭️  Recordatorio 7 días omitido para ${brand.email} (preferencias)`);
          return;
        }
      } else if (daysRemaining === 3) {
        const reminder3Enabled = await notificationPreferencesService.isNotificationEnabled(
          brand.id,
          'reminder_3days'
        );
        if (!reminder3Enabled) {
          console.log(`⏭️  Recordatorio 3 días omitido para ${brand.email} (preferencias)`);
          return;
        }
      }

      const amount = this.formatCOP(await this.getPlanAmount(brand.plan));
      let html: string;
      let subject: string;

      if (daysRemaining === 7) {
        // Recordatorio 7 días antes (urgencia baja)
        html = reminder7DaysEmail(
          { name: brand.name, email: brand.email },
          daysRemaining,
          amount
        );
        subject = 'Recordatorio: Tu suscripción vence en 7 días';
      } else if (daysRemaining === 3) {
        // Recordatorio 3 días antes (urgencia alta)
        html = reminder3DaysEmail(
          { name: brand.name, email: brand.email },
          daysRemaining,
          amount
        );
        subject = '⚠️ Urgente: Tu suscripción vence en 3 días';
      } else if (daysRemaining === 0) {
        // Notificación el día del vencimiento
        html = expirationTodayEmail(
          { name: brand.name, email: brand.email },
          amount
        );
        subject = '🚨 Tu suscripción vence hoy';
      } else {
        // Para otros días, usar template de 7 días con días personalizados
        html = reminder7DaysEmail(
          { name: brand.name, email: brand.email },
          daysRemaining,
          amount
        );
        subject = `Recordatorio: Tu suscripción vence en ${daysRemaining} días`;
      }

      await emailService.sendEmail({
        to: brand.email,
        subject,
        html,
      });

      console.log(`✅ Recordatorio de vencimiento enviado a ${brand.email} (${daysRemaining} días)`);
    } catch (error) {
      console.error(`❌ Error al enviar recordatorio a ${brand.email}:`, error);
      throw error;
    }
  }

  /**
   * Envía notificación de suspensión de cuenta
   * 
   * @param brand - Información de la marca
   * 
   * Requirement 13.5: Enviar notificación de suspensión si no se renueva
   */
  async sendSuspensionNotice(brand: Brand): Promise<void> {
    try {
      // Verificar si el email está habilitado
      const emailEnabled = await notificationPreferencesService.isNotificationEnabled(
        brand.id,
        'email'
      );

      if (!emailEnabled) {
        console.log(`⏭️  Notificación de suspensión omitida para ${brand.email} (preferencias)`);
        return;
      }

      const amount = this.formatCOP(await this.getPlanAmount(brand.plan));

      const html = suspensionEmail(
        { name: brand.name, email: brand.email },
        amount
      );

      await emailService.sendEmail({
        to: brand.email,
        subject: 'Cuenta Suspendida - Acción Requerida',
        html,
      });

      console.log(`✅ Notificación de suspensión enviada a ${brand.email}`);
    } catch (error) {
      console.error(`❌ Error al enviar notificación de suspensión a ${brand.email}:`, error);
      throw error;
    }
  }

  /**
   * Envía confirmación de renovación exitosa
   * 
   * @param brand - Información de la marca
   * 
   * Requirement 13.6: Enviar confirmación de renovación exitosa
   */
  async sendRenewalConfirmation(brand: Brand): Promise<void> {
    try {
      // Verificar si el email está habilitado
      const emailEnabled = await notificationPreferencesService.isNotificationEnabled(
        brand.id,
        'email'
      );

      if (!emailEnabled) {
        console.log(`⏭️  Confirmación de renovación omitida para ${brand.email} (preferencias)`);
        return;
      }

      const amount = this.formatCOP(await this.getPlanAmount(brand.plan));
      const daysRemaining = await this.subscriptionService.getDaysRemaining(brand.id) || 30;
      
      // Obtener información de suscripción para la nueva fecha de vencimiento
      const subscriptionInfo = await this.subscriptionService.getSubscriptionInfo(brand.id);
      const newExpirationDate = subscriptionInfo.endDate 
        ? new Date(subscriptionInfo.endDate).toLocaleDateString('es-CO', {
            year: 'numeric',
            month: 'long',
            day: 'numeric'
          })
        : 'No disponible';

      const html = renewalConfirmationEmail(
        { name: brand.name, email: brand.email },
        newExpirationDate,
        amount,
        daysRemaining
      );

      await emailService.sendEmail({
        to: brand.email,
        subject: '✅ Renovación Exitosa - Lookitry',
        html,
      });

      console.log(`✅ Confirmación de renovación enviada a ${brand.email}`);
    } catch (error) {
      console.error(`❌ Error al enviar confirmación de renovación a ${brand.email}:`, error);
      throw error;
    }
  }

  /**
   * Envía alerta de uso cuando se alcanza un porcentaje del límite mensual
   * 
   * @param brand - Información de la marca
   * @param percentage - Porcentaje de uso alcanzado (80 o 100)
   * @param used - Número de generaciones usadas
   * @param limit - Límite total de generaciones
   * 
   * Requirements: 13.7, 13.8, 13.9, 13.10
   */
  async sendUsageAlert(
    brand: Brand,
    percentage: number,
    used: number,
    limit: number
  ): Promise<void> {
    try {
      // Verificar si las alertas de uso están habilitadas
      const usageAlertsEnabled = await notificationPreferencesService.isNotificationEnabled(
        brand.id,
        'usage_alerts'
      );

      if (!usageAlertsEnabled) {
        console.log(`⏭️  Alerta de uso omitida para ${brand.email} (preferencias)`);
        return;
      }

      const amount = this.formatCOP(await this.getPlanAmount(brand.plan));
      const daysRemaining = await this.subscriptionService.getDaysRemaining(brand.id) || 0;
      let html: string;
      let subject: string;

      if (percentage >= 100) {
        // Alerta 100% - límite alcanzado
        html = usageAlert100Email(
          { name: brand.name, email: brand.email },
          limit,
          daysRemaining,
          amount
        );
        subject = '🚫 Límite de Generaciones Alcanzado';
      } else if (percentage === 80) {
        // Alerta 80% exacto - advertencia
        html = usageAlert80Email(
          { name: brand.name, email: brand.email },
          used,
          limit,
          daysRemaining,
          amount
        );
        subject = '⚠️ Alerta: Has usado el 80% de tus generaciones';
      } else {
        // Para otros porcentajes, usar template de 80% con subject personalizado
        html = usageAlert80Email(
          { name: brand.name, email: brand.email },
          used,
          limit,
          daysRemaining,
          amount
        );
        subject = `⚠️ Alerta: Has usado el ${percentage}% de tus generaciones`;
      }

      await emailService.sendEmail({
        to: brand.email,
        subject,
